        idx = data[syms[0]].index
        n = len(idx)

        result = {
            sym: pd.DataFrame({'signal': np.zeros(n), 'size_pct': np.zeros(n)}, index=idx)
            for sym in syms
        }

        rebal_freq = self.params.get('rebal_freq', 21)
        target_vol = self.params.get('target_vol', 0.15)
        max_total = self.params.get('max_total', 0.90)
