        closes = {sym: data[sym]['close'].values.astype(float) for sym in syms if sym in data}

        equity_assets = [s for s in ['SPY', 'QQQ', 'IWM', 'VTI', 'EFA'] if s in closes]
        safe_assets = [s for s in ['TLT', 'AGG', 'GLD'] if s in closes]

        def momentum_12_1(sym, bar):
            c = closes[sym]
            if bar < 252 or c[bar - 252] <= 0 or c[bar - 21] <= 0:
                return None
            return (c[bar - 21] / c[bar - 252]) - 1.0

        def above_sma200(sym, bar):
            c = closes[sym]
            if bar < 200:
                return False
            return c[bar] > np.mean(c[bar - 200: bar])

        def asset_vol(sym, bar, lb=63):
            c = closes[sym]
            if bar < lb + 1:
                return 0.15
            rets = np.diff(np.log(np.maximum(c[bar - lb: bar + 1], 1e-10)))
            return max(float(np.std(rets) * np.sqrt(252)), 0.04)

        def portfolio_vol(weights, bar, lb=63):
            if not weights or bar < lb + 1:
                return 0.15
            port_rets = np.zeros(lb)
            for sym, w in weights.items():
                if sym in closes:
                    c = closes[sym]
                    r = np.diff(np.log(np.maximum(c[bar - lb: bar + 1], 1e-10)))
                    port_rets += w * r
            return max(float(np.std(port_rets) * np.sqrt(252)), 0.04)

        warmup = 260
        last_rebal = -rebal_freq
        cur_holdings = {}

        for bar in range(n):
            for sym in syms:
                if sym in cur_holdings:
                    result[sym]['signal'].iat[bar] = 1.0
                    result[sym]['size_pct'].iat[bar] = cur_holdings[sym]
                else:
                    result[sym]['signal'].iat[bar] = 0.0
                    result[sym]['size_pct'].iat[bar] = 0.0

            if bar < warmup or (bar - last_rebal) < rebal_freq:
                continue

            eq_scores = {sym: momentum_12_1(sym, bar) for sym in equity_assets}
            eq_scores = {sym: s for sym, s in eq_scores.items() if s is not None}
            sa_scores = {sym: momentum_12_1(sym, bar) for sym in safe_assets}
            sa_scores = {sym: s for sym, s in sa_scores.items() if s is not None}

            eq_candidates = [
                (sym, eq_scores[sym]) for sym in equity_assets
                if sym in eq_scores and eq_scores[sym] > 0 and above_sma200(sym, bar)
            ]
            eq_candidates.sort(key=lambda x: x[1], reverse=True)
            selected_eq = [sym for sym, _ in eq_candidates[:top_n]]

            best_safe = max(sa_scores, key=sa_scores.get) if sa_scores else None

            cur_holdings = {}

            if not selected_eq:
                if best_safe:
                    cur_holdings[best_safe] = max_total
            else:
                vols = {sym: asset_vol(sym, bar) for sym in selected_eq}
                inv_vols = {sym: 1.0 / v for sym, v in vols.items()}
                total_inv = sum(inv_vols.values())
                rp_weights = {sym: inv_vols[sym] / total_inv for sym in selected_eq}

                pv = portfolio_vol(rp_weights, bar)
                vol_scale = min(target_vol / pv, 1.5)

