                else:
                    eq_alloc = max_total * vol_scale
                    safe_alloc = max_total - eq_alloc
                    for sym in selected_eq:
                        cur_holdings[sym] = rp_weights[sym] * eq_alloc
                    if best_safe is not None and safe_alloc > 0.01:
                        cur_holdings[best_safe] = safe_alloc

                total = sum(cur_holdings.values())
                if total > max_total:
                    fac = max_total / total
                    cur_holdings = {sym: w * fac for sym, w in cur_holdings.items()}

            last_rebal = bar

            for sym in syms:
                if sym in cur_holdings:
                    result[sym]['signal'].iat[bar] = 1.0
                    result[sym]['size_pct'].iat[bar] = cur_holdings[sym]
                else:
                    result[sym]['signal'].iat[bar] = 0.0
                    result[sym]['size_pct'].iat[bar] = 0.0

        return result
